INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '81dd06e4-0334-4ab4-bb80-91edec02d18b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Anthropic API Prompt Engineering — System Prompts, Few-Shot, CoT, and Structured Output$escape$,
  $escape$The Anthropic API's `system` parameter is a first-class field — not a prefixed user message. Pass your persona, constraints, and output format there, keeping the `messages` array clean for dialogue. Few-shot examples belong in the `messages` array as alternating `user`/`assistant` turns before your real query; Claude treats them as demonstrated behavior, not instructions.

For chain-of-thought on claude-sonnet-4-6 or opus-4-6, enable extended thinking via `thinking: { type: 'enabled', budget_tokens: 5000 }`. The response includes a `thinking` content block you can log separately — never surface it raw to end users. For structured output, skip prompt-hacking and use the `tools` parameter: define a single tool whose `input_schema` is your target JSON shape, then set `tool_choice: { type: 'tool', name: 'your_tool' }` to force a call. Claude fills the schema reliably without escape-hatch prose.$escape$,
  $escape$import Anthropic from '@anthropic-ai/sdk';

const client = new Anthropic();

const response = await client.messages.create({
  model: 'claude-sonnet-4-6',
  max_tokens: 1024,
  system: 'You are a JSON extraction engine. Return only structured data.',
  tools: [{
    name: 'extract_entity',
    description: 'Extract named entities from text',
    input_schema: {
      type: 'object',
      properties: {
        entities: { type: 'array', items: { type: 'string' } },
        sentiment: { type: 'string', enum: ['positive', 'negative', 'neutral'] }
      },
      required: ['entities', 'sentiment']
    }
  }],
  tool_choice: { type: 'tool', name: 'extract_entity' },
  messages: [{ role: 'user', content: 'Claude 4 launches with improved reasoning.' }]
});

const result = (response.content[0] as Anthropic.ToolUseBlock).input;
console.log(result);$escape$,
