INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3d737d1f-c5ac-4461-9255-e1111beda202',
  '00000000-0000-0000-0000-000000000001',
  $escape$Anthropic API + Hugging Face — Building a Hybrid RAG Pipeline Without Paying for Embeddings$escape$,
  $escape$When building RAG systems with Claude, you don't have to choose between Hugging Face's model ecosystem and Anthropic's generation quality — they compose cleanly. HF's `sentence-transformers` models handle embedding and retrieval locally at zero API cost; `client.messages.create()` handles synthesis with Claude's reasoning depth. The pattern: embed your corpus with `all-MiniLM-L6-v2`, retrieve top-k chunks via cosine similarity, then inject them into the `user` message. Claude's 200k context window means you can pass substantial retrieved content without aggressive chunking. For preprocessing, HF pipelines add real leverage — run zero-shot classification or NER before deciding what to retrieve, then pass only high-signal context. Avoid dumping raw HF pipeline outputs directly into Claude; filter by confidence threshold first to avoid poisoning the context with low-signal extractions. For adaptive pipelines, expose retrieval as a `tool` in `tools=[...]` and let Claude decide when to invoke it via `tool_use` content blocks — this eliminates unnecessary retrievals on questions Claude can answer directly from its weights.$escape$,
  $escape$from transformers import pipeline
import anthropic
import numpy as np

embedder = pipeline("feature-extraction", model="sentence-transformers/all-MiniLM-L6-v2", truncation=True)
client = anthropic.Anthropic()

def embed(text: str) -> np.ndarray:
    vecs = embedder(text)[0]  # shape: (tokens, 384)
    return np.mean(vecs, axis=0)

def retrieve(query: str, corpus: list[str], corpus_embs: list, top_k=3) -> list[str]:
    q = embed(query)
    scores = [np.dot(q, e) / (np.linalg.norm(q) * np.linalg.norm(e)) for e in corpus_embs]
    return [corpus[i] for i in np.argsort(scores)[-top_k:][::-1] if scores[i] > 0.4]

context = "\n\n".join(retrieve("How does attention work?", corpus, corpus_embeddings))
response = client.messages.create(
    model="claude-opus-4-6",
    max_tokens=512,
    messages=[{"role": "user", "content": f"Context:\n{context}\n\nAnswer concisely."}]
)$escape$,
  $escape$python$escape$,
