INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c3596624-2da6-42e2-ba6b-7f3b1e043c27',
  '00000000-0000-0000-0000-000000000001',
  $escape$Anthropic API — Streaming Tool Use Responses Without Dropping Input JSON$escape$,
  $escape$When you stream a tool use response from the Anthropic API, the tool's input JSON arrives fragmented across multiple `input_json_delta` events — not as a single block. A common bug is reading only the final `content_block_stop` and wondering why `tool_use.input` is empty. You must accumulate `delta.partial_json` across all `content_block_delta` events where `delta.type === 'input_json_delta'`, then parse the concatenated string once the block closes. Each tool call is scoped to a `content_block_start` event with `content_block.type === 'tool_use'`, which gives you the `id` and `name` upfront. Track blocks by index. The same stream can contain interleaved `text_delta` and `input_json_delta` events across different block indexes — handle both. After the stream ends, reconstruct the full `messages` array (including the assistant turn with all content blocks) before appending a `tool` role message with your function results. Skipping this causes a 400: missing assistant message in multi-turn tool loops.$escape$,
  $escape$import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();
const toolInputs: Record<number, string> = {};

const stream = client.messages.stream({
  model: "claude-opus-4-5",
  max_tokens: 1024,
  tools: [{ name: "get_weather", description: "Get weather", input_schema: { type: "object", properties: { location: { type: "string" } }, required: ["location"] } }],
  messages: [{ role: "user", content: "What's the weather in Tokyo?" }],
});

for await (const event of stream) {
  if (event.type === "content_block_delta" && event.delta.type === "input_json_delta") {
    toolInputs[event.index] = (toolInputs[event.index] ?? "") + event.delta.partial_json;
  }
  if (event.type === "content_block_stop") {
    const raw = toolInputs[event.index];
    if (raw) console.log("Tool input:", JSON.parse(raw));
  }
}$escape$,
  $escape$typescript$escape$,
