INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4b7ccb90-7b8d-4a37-84ba-d70e25bef91c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Anthropic API + Groq — Mixing Fast Open-Source Inference into Your Claude Pipelines$escape$,
  $escape$Groq's inference platform delivers ~500 tokens/sec on models like `llama-3.3-70b-versatile` and `llama-3.1-8b-instant` — roughly 10–20x faster than most hosted APIs. For Anthropic API developers, the practical use case is hybrid pipelines: route latency-sensitive, lower-stakes steps (intent classification, tool-call routing, semantic gating) to Groq, then invoke `claude.messages.create()` only where Claude's reasoning quality justifies the cost.

Groq's API is OpenAI-compatible, not Anthropic-compatible — you cannot point `anthropic.Anthropic()` at Groq's base URL. Instead, instantiate `openai.OpenAI` with `base_url='https://api.groq.com/openai/v1'`. Response shapes differ: Groq returns `choices[0].message.content` (OpenAI schema) while Anthropic returns `message.content[0].text`. Handle both explicitly — shared abstractions here will bite you in production.

Current Groq model roster: `llama-3.3-70b-versatile`, `llama-3.1-8b-instant`, `mixtral-8x7b-32768`, `gemma2-9b-it`. Use `8b-instant` for sub-100ms classifications. Reserve `claude-sonnet-4-6` or `claude-opus-4-6` for the pipeline steps where depth and instruction-following actually matter.$escape$,
  $escape$import anthropic
from openai import OpenAI

claude = anthropic.Anthropic()
groq = OpenAI(api_key="gsk_...", base_url="https://api.groq.com/openai/v1")

def classify_intent(text: str) -> str:
    res = groq.chat.completions.create(
        model="llama-3.1-8b-instant",
        messages=[{"role": "user", "content": f"Classify intent (one word): {text}"}],
        max_tokens=10,
    )
    return res.choices[0].message.content.strip()

def generate_summary(text: str, intent: str) -> str:
    msg = claude.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=300,
        messages=[{"role": "user", "content": f"[Intent: {intent}]\n\n{text}"}],
    )
    return msg.content[0].text$escape$,
  $escape$python$escape$,
