INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e2ae9953-c0e4-44ba-bd10-df449a6cb0aa',
  '00000000-0000-0000-0000-000000000001',
  $escape$Anthropic API + Voyage AI — The Right Way to Do Embeddings in Claude Pipelines$escape$,
  $escape$Claude's API has no native embeddings endpoint — Anthropic's recommended solution is Voyage AI (voyage-3, voyage-3-lite, voyage-code-3). voyage-3 produces 1024-dim L2-normalized vectors and outperforms OpenAI's text-embedding-3-large on MTEB benchmarks for most general retrieval tasks. For code search, voyage-code-3 handles mixed natural-language and code queries far better than any general model.

The standard RAG pattern for Claude: embed docs with Voyage, retrieve top-k by cosine similarity, then pass chunks to claude-sonnet-4-6 or claude-opus-4-6 for generation. For tighter context windows and lower token costs, add a reranking step with Voyage's rerank-2 before calling Claude — it narrows the retrieved set before it ever hits your token budget.

Model comparison in brief: voyage-3 is the go-to for general text retrieval; voyage-3-lite costs ~60% less with minimal quality loss for most queries; voyage-code-3 is mandatory for any code-heavy search. All three sit in the same virtual environment as the anthropic SDK — complementary API keys, zero friction.$escape$,
  $escape$import voyageai
import anthropic
import numpy as np

vo = voyageai.Client()  # VOYAGE_API_KEY env var
client = anthropic.Anthropic()  # ANTHROPIC_API_KEY env var

docs = ["Claude 3.5 uses extended thinking", "Llama 3 is fully open-weights"]
query = "Which model exposes its reasoning chain?"

doc_embeddings = np.array(vo.embed(docs, model="voyage-3").embeddings)
query_embedding = np.array(vo.embed([query], model="voyage-3").embeddings[0])

scores = doc_embeddings @ query_embedding  # vectors are L2-normalized
top_doc = docs[scores.argmax()]

response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=256,
    messages=[{"role": "user", "content": f"Context: {top_doc}\n\n{query}"}]
)
print(response.content[0].text)$escape$,
  $escape$python$escape$,
