INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '046fb075-baac-4cb8-8522-b25d5adbe949',
  '00000000-0000-0000-0000-000000000001',
  $escape$Anthropic API Cost Management — Token Counting, Caching, and Batching$escape$,
  $escape$Three levers cut Anthropic API costs significantly. First, pre-flight token counting: `client.messages.count_tokens()` accepts the same payload as `messages.create()` and returns exact input token counts before you commit to a request — use this to gate expensive calls or enforce budget limits per user. Second, prompt caching: mark static content (system prompts, large documents, few-shot examples) with `cache_control: { type: 'ephemeral' }`. Cached tokens cost 10% of base input price on reads and 25% on writes, with a 5-minute TTL that resets on each cache hit. For a 10K-token system prompt hit 100 times per hour, that's a 90% reduction on those tokens alone. Third, the Message Batches API (`client.messages.batches.create()`) processes up to 10,000 requests asynchronously at 50% cost — ideal for classification, embedding prep, or offline summarization. For model selection: Haiku 3.5 handles retrieval filtering and intent classification; Sonnet 4 owns most production tasks; Opus 4 only when multi-step reasoning or accuracy is non-negotiable. Never default to Opus.$escape$,
  $escape$import Anthropic from '@anthropic-ai/sdk';

const client = new Anthropic();

// Pre-flight token count
const { input_tokens } = await client.messages.countTokens({
  model: 'claude-sonnet-4-5',
  system: [{ type: 'text', text: SYSTEM_PROMPT, cache_control: { type: 'ephemeral' } }],
  messages: [{ role: 'user', content: userMessage }],
});

if (input_tokens > 8000) throw new Error('Payload too large');

// Cached message create
const response = await client.messages.create({
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 512,
  system: [{ type: 'text', text: SYSTEM_PROMPT, cache_control: { type: 'ephemeral' } }],
  messages: [{ role: 'user', content: userMessage }],
});$escape$,
